sp_angular_provider.script:
function scmNavFlyoverManager(
    $rootScope,
    scmFlyover,
    $location,
    $httpParamSerializer,
    spUtil,
) {
    "use strict";

    const NAV_PREFIX = "scm_nav";
    const UTILS_SCRIPT_NAME = "x_680259_scm.NavigationManagerAJAX";

    let navConfigs = [];

    const locationParams = $location.search();
    let currentPage = locationParams.id;

    getConfigsFromServer();

    const flyover = new scmFlyover("", $rootScope);
    flyover.setAppendToBody(true);

    $rootScope.$on("$locationChangeStart", () => {
        runOnLocationChange();
    });

    const factory = {
        navigate: navigate,
        removeNavParams: removeNavParams,
    };

    return factory;

    function runOnLocationChange() {
        const params = $location.search();
        if (currentPage != params.id) {
            currentPage = params.id;
            getConfigsFromServer();
            return;
        }

        const navParams = getNavParams();

        if (!navParams[NAV_PREFIX]) return;

        const decodedNavParams = decodeNavParams(navParams);
        navConfigs
            .filter((config) => config.name == navParams[NAV_PREFIX])
            .forEach((config) => {
                let title, options, beforeOpen;

                (function (navParams, renderResponse) {
                    try {
                        beforeOpen = eval(config.beforeOpen);
                    } catch (error) {
                        console.error(
                            "Failed to evaluate 'Before open' script for config " +
                                config.name +
                                ": " +
                                error,
                        );
                    }
                })(decodedNavParams, config.render);

                if (!beforeOpen) return;

                (function (navParams) {
                    try {
                        title = eval(config.title);
                    } catch (error) {
                        console.error(
                            "Failed to evaluate 'Title' script for config " +
                                config.name +
                                ": " +
                                error,
                        );
                    }
                })(decodedNavParams);

                (function (navParams) {
                    try {
                        options = eval(config.options);
                    } catch (error) {
                        console.error(
                            "Failed to evaluate 'Options' script for config " +
                                config.name +
                                ": " +
                                error,
                        );
                    }
                })(decodedNavParams);

                flyover.setTitle(title);
                flyover.setOptions(options);
                flyover.setWidgetId(config.widget_id);
                flyover.onClose(cleanupNavParams);
                flyover.open();
            });
    }

    function navigate(navOptions) {
        if (flyover.isOpen()) {
            flyover.close().then(() => {
                setParamsToUrl(navOptions);
            });
        } else {
            setParamsToUrl(navOptions);
        }
    }

    function setParamsToUrl(navOptions) {
        const navParams = encodeNavParams(navOptions);
        navParams.spa = 1;

        const params = $location.search();
        angular.extend(params, navParams);

        $location.search($httpParamSerializer(params));
    }

    function removeNavParams(navOptionsToRemove) {
        const currentParams = $location.search();
        navOptionsToRemove.forEach((key) => delete currentParams[key]);
        $location.search($httpParamSerializer(currentParams));
    }

    function getNavParams() {
        const params = $location.search();
        return Object.keys(params)
            .filter((key) => key.startsWith(NAV_PREFIX))
            .reduce((cur, key) => {
                return Object.assign(cur, { [key]: params[key] });
            }, {});
    }

    function cleanupNavParams() {
        const currentParams = $location.search();
        const currentNavParams = getNavParams();
        Object.keys(currentNavParams).forEach(
            (key) => delete currentParams[key],
        );
        $location.search($httpParamSerializer(currentParams));
    }

    function encodeNavParams(params) {
        const encodedParams = {};
        Object.keys(params).forEach((param) => {
            if (param == "name") {
                encodedParams[NAV_PREFIX] = params[param];
            } else {
                encodedParams[NAV_PREFIX + "_" + param] = params[param];
            }
        });
        return encodedParams;
    }

    function decodeNavParams(params) {
        const decodedParams = {};
        Object.keys(params).forEach((param) => {
            if (param == NAV_PREFIX) {
                decodedParams["name"] = params[param];
            } else {
                decodedParams[param.slice(NAV_PREFIX.length + 1)] =
                    params[param];
            }
        });
        return decodedParams;
    }

    function getConfigsFromServer() {
        const locationParams = $location.search();
        if (!locationParams.id) {
            navConfigs = scm_scratchpad.navigationConfigs = [];
            return;
        }
        scm_scratchpad
            .glideAjax(UTILS_SCRIPT_NAME, "getPageConfigs", {
                page: locationParams.id,
                params: JSON.stringify(locationParams),
            })
            .then(function (configs) {
                navConfigs = scm_scratchpad.navigationConfigs =
                    JSON.parse(configs);
                runOnLocationChange();
            });
    }
}
